joystick.code:
/* ============================================================
   VirtualJoystick — floating, hand-rolled, Phaser 3.80, no plugin.
   - Appears where the pointer first presses, thumb drags within a ring.
   - .vector  -> { x, y } each in [-1,1]; magnitude (hypot) is analog 0..1.
   - Auto-hides on release. Touch + mouse. Coexists with WASD.
   Usage:
     this.stick = new VirtualJoystick(this);   // in create()
     const v = this.stick.vector;               // in update()/moverPlayer
   ============================================================ */
class VirtualJoystick {
  /**
   * @param {Phaser.Scene} scene
   * @param {object} [opts]
   * @param {number} [opts.radius=70]   max travel of thumb from center (px)
   * @param {number} [opts.deadZone=0.12] ignore tiny drifts (fraction of radius)
   * @param {number} [opts.depth=50]     render depth (above world, below modals)
   * @param {boolean}[opts.staticBase=false] if true, base stays put after spawn
   */
  constructor(scene, opts = {}) {
    this.scene   = scene;
    this.radius  = opts.radius   ?? 70;
    this.deadZone= opts.deadZone ?? 0.12;
    this.depth   = opts.depth    ?? 50;
    this.followBase = !opts.staticBase; // base recenters if you drag past edge

    this.active   = false;     // is the stick currently engaged?
    this.pointerId = -1;       // which pointer owns the stick
    this.baseX = 0; this.baseY = 0;
    this.curX  = 0; this.curY  = 0;
    this._vec  = { x: 0, y: 0 };

    // --- visuals (created hidden) ---
    this.base = scene.add.circle(0, 0, this.radius, 0xffffff, 0.10)
      .setStrokeStyle(3, 0xffffff, 0.35).setDepth(this.depth).setVisible(false)
      .setScrollFactor(0);
    this.thumb = scene.add.circle(0, 0, this.radius * 0.42, 0xffffff, 0.28)
      .setStrokeStyle(2, 0xffffff, 0.7).setDepth(this.depth + 1).setVisible(false)
      .setScrollFactor(0);

    // allow >1 simultaneous pointer so a UI tap can't steal the stick (touch).
    if (scene.input.addPointer) scene.input.addPointer(2);

    // bound handlers so we can remove them on destroy
    this._onDown = (p) => this._down(p);
    this._onMove = (p) => this._move(p);
    this._onUp   = (p) => this._up(p);
    scene.input.on('pointerdown', this._onDown);
    scene.input.on('pointermove', this._onMove);
    scene.input.on('pointerup',   this._onUp);
    scene.input.on('pointerupoutside', this._onUp);
    // if the canvas loses the pointer (mouse leaves window), release.
    scene.input.on('gameout', () => this._release());
  }

  /** Override to reject presses on HUD/buttons. Return false to ignore. */
  canStart(pointer) {
    // Don't grab the stick while a modal (level-up/game-over) is up.
    return !(this.scene.paused || this.scene.over);
  }

  _down(p) {
    if (this.active) return;               // already owned by another finger
    if (!this.canStart(p)) return;
    this.active = true;
    this.pointerId = p.id;
    // worldX/worldY: camera-transformed; equals screen coords when no scroll/zoom.
    this.baseX = this.curX = p.worldX;
    this.baseY = this.curY = p.worldY;
    this.base.setPosition(this.baseX, this.baseY).setVisible(true);
    this.thumb.setPosition(this.baseX, this.baseY).setVisible(true);
    this._recompute();
  }

  _move(p) {
    if (!this.active || p.id !== this.pointerId) return;
    this.curX = p.worldX;
    this.curY = p.worldY;
    this._recompute();
  }

  _up(p) {
    if (!this.active || p.id !== this.pointerId) return;
    this._release();
  }

  _release() {
    this.active = false;
    this.pointerId = -1;
    this._vec.x = 0; this._vec.y = 0;
    this.base.setVisible(false);
    this.thumb.setVisible(false);
  }

  _recompute() {
    let dx = this.curX - this.baseX;
    let dy = this.curY - this.baseY;
    let dist = Math.hypot(dx, dy);
    const R = this.radius;

    if (dist > R) {
      // clamp thumb to ring; optionally drag the base along (floating feel).
      if (this.followBase) {
        const over = dist - R;
        this.baseX += (dx / dist) * over;
        this.baseY += (dy / dist) * over;
        this.base.setPosition(this.baseX, this.baseY);
        dx = this.curX - this.baseX;
        dy = this.curY - this.baseY;
        dist = R;
      } else {
        dx = (dx / dist) * R;
        dy = (dy / dist) * R;
        dist = R;
      }
    }
    this.thumb.setPosition(this.baseX + dx, this.baseY + dy);

    // analog magnitude with dead zone, normalized 0..1
    let mag = dist / R;
    if (mag < this.deadZone) { this._vec.x = 0; this._vec.y = 0; return; }
    // rescale so the dead zone edge maps to 0 (smooth start)
    mag = (mag - this.deadZone) / (1 - this.deadZone);
    if (dist === 0) { this._vec.x = 0; this._vec.y = 0; return; }
    const ux = dx / dist, uy = dy / dist; // unit direction
    this._vec.x = ux * mag;
    this._vec.y = uy * mag;
  }

  /** {x,y} each in [-1,1]; hypot(x,y) is analog speed 0..1. (0,0) when idle. */
  get vector() { return this._vec; }
  /** true while a finger/mouse is driving the stick. */
  get isActive() { return this.active; }

  destroy() {
    const i = this.scene.input;
    i.off('pointerdown', this._onDown);
    i.off('pointermove', this._onMove);
    i.off('pointerup',   this._onUp);
    i.off('pointerupoutside', this._onUp);
    this.base.destroy();
    this.thumb.destroy();
  }
}

